import java.io.*;
import java.util.*;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        System.out.println("Hello, " + Encode.forHtml(name) + "!");

        // User input is properly escaped to prevent XSS attack
        System.out.println(Encode.forHtml("<script>alert('XSS attack!')</script>"));
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
